#include<bits/stdc++.h>#include<ext/pb_ds/assoc_container.hpp>#include<ext/pb_ds/tree_policy.hpp>using namespace std;using namespace __gnu_pbds; #define ll long long#define nl "\n"#define FASTER ios_base::sync_with_stdio(0); cin.tie(0); cout.tie(0);template <typename T> using ordered_set = tree<T,null_type, less<T>, rb_tree_tag, tree_order_statistics_node_update>; const ll N = 1e5+10;const ll mod = 1e9+7;const ll INF = 1e9+10; void solve(){    ll n,k;    cin>>n>>k;    set<ll>s, completeA, ans;    for(int i=0; i<n; i++){        ll x;        cin>>x;        s.insert(x);    }    completeA = s;    bool ok = true;    while(!s.empty()){        ll first_val = *s.begin();        for(int i=1; i*first_val<=k; i++){            if(!completeA.count(i*first_val)){                ok = false;                break;            }            s.erase(i*first_val);        }        if(ok) ans.insert(first_val);    }        if(ok) {        cout<<ans.size()<<nl;        for(auto &av:ans){            cout<<av<<" ";        }        cout<<nl;    } else cout<<-1<<nl;} int main(){    FASTER    ll t;    cin>>t;    while(t--){        solve();    }}